checker_dsl:
EXISTS (`BinaryExpr test`) {
  AND {
    OR {
      EXISTS (`EqualityTest guard`, `SsaDefinition v`, `CompileTimeConstantExpr c1`, `CompileTimeConstantExpr c2`) {
        AND {
          (`test is an EqualityTest`),
          (`guard is an EqualityTest`),
          (`guard has operands v.getARead() and c1`),
          (`test has operands v.getARead() and c2`),
          (`c1.getIntValue() = c2.getIntValue()`),
          (`v.getSourceVariable().getType() is an IntegralType`),
          (`guard controls the basic block containing test`)
        }
      },
      AND {
        NOT { EXISTS (`EqualityTest g`) { (`uselessEqTest(test, _, g)`) } },
        EXISTS (`NoReason nr`) { (`constCond(test, _, nr)`) }
      },
      AND {
        NOT { EXISTS (`EqualityTest g`) { (`uselessEqTest(test, _, g)`) } },
        NOT { EXISTS (`NoReason nr`) { (`constCond(test, _, nr)`) } },
        EXISTS (`CondReason r`) { (`constCond(test, _, r)`) }
      }
    },
    NOT {
      OR {
        AND {
          OR {
            EXISTS (`SsaDefinition v`) {
              AND {
                (`test is a ComparisonExpr`),
                OR {
                  (`test has operands increaseOrDecreaseOfVar(v) and v.getARead()`),
                  (`test has operands v.getARead() and increaseOrDecreaseOfVar(v)`)
                }
              }
            },
            AND {
              (`test is a ComparisonExpr`),
              (`test.getLesserOperand() = overFlowCand()`),
              (`test.getGreaterOperand() is an IntegerLiteral with value 0`)
            }
          },
          (`test.getEnclosingStmt() is not a LoopStmt`)
        },
        EXISTS (`IfStmt ifstmt`, `ThrowStmt throw`, `RefType exc`) {
          AND {
            (`ifstmt.getCondition() = test`),
            OR {
              (`ifstmt.getThen() = throw`),
              (`ifstmt.getThen() is a SingletonBlock with single statement throw`)
            },
            (`throw.getExpr() is a ClassInstanceExpr constructing type exc`),
            (`exc has qualified name "java.util.ConcurrentModificationException"`)
          }
        }
      }
    },
    NOT {
      EXISTS (`AssertStmt assert`) {
        (`assert.getExpr() is an ancestor of test`)
      }
    }
  }
}
